local function ip_to_int(ip_str)
    local o1, o2, o3, o4 = ip_str:match("^(%d+)%.(%d+)%.(%d+)%.(%d+)$")
    if not o1 then
        return nil
    end
    o1, o2, o3, o4 = tonumber(o1), tonumber(o2), tonumber(o3), tonumber(o4)
    if o1 > 255 or o2 > 255 or o3 > 255 or o4 > 255 then
        return nil
    end
    return o1 * 16777216 + o2 * 65536 + o3 * 256 + o4
end

local function is_ip_in_cidr(ip_str, cidr_ip, prefix_len)
