    end
    local mask = 0xFFFFFFFF - (2 ^ (32 - prefix_len) - 1)
    -- Use bit module for bitwise AND
    local bit = require "bit"
    return bit.band(ip_int, mask) == bit.band(cidr_int, mask)
end

